import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { handleError, handleSuccess } from '../utils';
import Navbar from "../../COMPONENTS/Navbar/Navbar"; // ✅ Ajout de la Navbar
import './Login.css';
import loginImage from '../pages/1.png';

function Login() {
    const [loginInfo, setLoginInfo] = useState({ email: '', password: '' });
    const navigate = useNavigate();

    const handleChange = (e) => {
        const { name, value } = e.target;
        setLoginInfo((prev) => ({ ...prev, [name]: value }));
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        const { email, password } = loginInfo;
        if (!email || !password) return handleError("Email and password are required");

        try {
            console.log("📤 Envoi des informations de connexion:", loginInfo);

            const response = await fetch("http://localhost:5001/auth/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(loginInfo),
            });

            const result = await response.json();
            console.log("🔐 Réponse du serveur:", result);

            const { success, message, jwtToken, name, role, _id } = result;

            if (success) {
                handleSuccess(message);
                localStorage.setItem("token", jwtToken);
                localStorage.setItem("loggedInUser", name);
                localStorage.setItem("userRole", role);
                localStorage.setItem("loggedInUserId", _id);
                localStorage.setItem("userEmail", email); 

                console.log("✅ User ID stocké:", _id);
                console.log("✅ Email stocké:", email);

                setTimeout(() => {
                    if (role === "business") navigate("/bussniess");
                    else if (role === "livreur") navigate("/livreure");
                    else if (role === "admin") navigate("/DashboardHome");
                    else navigate("/user/:activepage");
                }, 1000);
            } else {
                handleError(message);
            }
        } catch (err) {
            console.error("❌ Erreur lors du login:", err.message);
            handleError(err.message);
        }
    };

    return (
        <div className='login-page'>
            <Navbar />  {/* ✅ Ajout de la Navbar en haut de la page */}
            <div className='login-container'>
                <div className='login-image'>
                    <img src={loginImage} alt='Login Illustration' />
                </div>
                <div className='login-form'>
                    <h1>Welcome Back</h1>
                    <p>Please enter your credentials to continue</p>
                    <form onSubmit={handleLogin}>
                        <input 
                            type='email' 
                            name='email' 
                            placeholder='Email Address' 
                            onChange={handleChange} 
                            value={loginInfo.email} 
                        />
                        <input 
                            type='password' 
                            name='password' 
                            placeholder='Password' 
                            onChange={handleChange} 
                            value={loginInfo.password} 
                        />
                        <button type='submit' className='login-button'>Login</button>
                        <p>Don't have an account? <Link to='/signup'>Sign up</Link></p>
                    </form>
                    <ToastContainer />
                </div>
            </div>
        </div>
    );
}

export default Login;
